private int findLargestOddRight(int[] nums, int start) {
    int maxOdd = 0;
    boolean foundOdd = false;
    for (int i = start + 1; i < nums.length; i++) {
        if (nums[i] % 2 != 0) {
            if (!foundOdd || nums[i] > maxOdd) {
                maxOdd = nums[i];
                foundOdd = true;
            }
        }
    }
    return foundOdd ? maxOdd : 0;
}

